solution_code:
#include <iostream>

int add(int a, int b);
int subtract(int a, int b);
int multiply(int a, int b);

int main() {
    int a{}, b{}, op{};
    std::cin >> a >> b >> op;

    int result { add(a, b) * (op == 1)
              + subtract(a, b) * (op == 2)
              + multiply(a, b) * (op == 3) };
    std::cout << result << '\n';

    return 0;
}

int add(int a, int b) { return a + b; }
int subtract(int a, int b) { return a - b; }
int multiply(int a, int b) { return a * b; }

