#include <iostream>

int double_it(int x);
int add_ten(int x);
int negate(int x);

int main() {
    int n{};
    std::cin >> n;
    std::cout << negate(add_ten(double_it(n))) << '\n';
    return 0;
}

int double_it(int x) { return x * 2; }
int add_ten(int x) { return x + 10; }
int negate(int x) { return -x; }
